def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-9
    for idx, capacity in enumerate(bins):
        if capacity == 0:
            priorities[idx] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) + (capacity % 5) * 3.7
            for k in range(1, int(capacity) * 2 + 3):
                if k % 4 == 0:
                    priority += np.tanh((ratio * k) / (k + epsilon)) * k
                elif k % 3 == 0:
                    priority -= np.cos(np.sqrt(abs(ratio - k)))
                else:
                    priority += np.log(k + ratio + epsilon) / (k**0.5 + epsilon)
            if int(capacity) % 4 == 3:
                priority *= 1.25
            else:
                priority /= 1.2
        elif 2 < ratio <= 3:
            priority = ((ratio ** 3) * np.log(capacity + 2)) ** 1.1
            for m in range(1, int(item) * 2):
                if m % 5 == 0:
                    priority += np.sin(m / (capacity + 1)) * 3
                else:
                    priority -= m / (item + epsilon) ** 1.5
            priority = max(priority, 0)
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.sqrt(capacity + 1)
            factor = 1
            for n in range(1, int(capacity) + 3):
                factor *= (ratio + np.log(n + 1) / (capacity + 1))
                if factor > 10:
                    break
            priority *= factor
            for q in range(1, int(item) + 2):
                if q % 2 == 1:
                    priority += np.exp(-q / (capacity + 1))
                else:
                    priority -= np.sqrt(q) / (item + epsilon)
            priority = max(priority, 0)
        elif 0.4 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon)
            total = 1
            for r in range(1, int(capacity // 2) + 1):
                val = (ratio ** r) * np.sin(r + ratio)
                if r % 3 == 0:
                    val *= -1
                total += val / (r + epsilon)
                if total > 3:
                    break
            priority *= total
        elif 0.1 < ratio <= 0.4:
            total = 0
            for j in range(1, int(capacity) + 5):
                val = ((ratio ** j) / (j + epsilon)) * np.cos(j * ratio)
                if j % 2 == 0:
                    val *= -1
                total += val
            priority = abs(total) + 0.25 * np.log(capacity + 1)
        else:
            priority = (1 / (ratio + epsilon)) ** 1.5
            penalty = 0
            for s in range(1, 6):
                penalty += np.log(s + ratio + epsilon) / (s ** 0.8 + epsilon)
            priority += penalty
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) + 3):
                if p % 3 == 0:
                    penalty += np.sqrt(p + 1)
                else:
                    penalty -= p * 0.15
                if penalty < 0:
                    penalty = 0
            priority += penalty
        if ratio > 1.5 and capacity % 2 == 0:
            priority *= 0.9
        elif ratio < 0.5 and capacity % 2 == 1:
            priority *= 1.2
        if priority < 0:
            priority = abs(priority) + np.random.rand()
        priorities[idx] = priority
    return priorities
